import{_ as a,o as n,c as i,ag as t}from"./chunks/framework.ePeAWSvT.js";const p=JSON.parse('{"title":"Screen Policy: 공지사항 (성원소식)","description":"","frontmatter":{},"headers":[],"relativePath":"공지사항_Screen_Policy_Final.md","filePath":"공지사항_Screen_Policy_Final.md"}'),s={name:"공지사항_Screen_Policy_Final.md"};function e(r,l,o,d,h,u){return n(),i("div",null,[...l[0]||(l[0]=[t(`<h1 id="screen-policy-공지사항-성원소식" tabindex="-1">Screen Policy: 공지사항 (성원소식) <a class="header-anchor" href="#screen-policy-공지사항-성원소식" aria-label="Permalink to &quot;Screen Policy: 공지사항 (성원소식)&quot;">​</a></h1><h2 id="■-screen-meta" tabindex="-1">■ Screen Meta <a class="header-anchor" href="#■-screen-meta" aria-label="Permalink to &quot;■ Screen Meta&quot;">​</a></h2><ul><li><strong>SCREEN_NAME</strong>: 공지사항 (성원소식)</li><li><strong>화면 목적</strong>: 성원애드피아 운영 공지, 이벤트, 보도자료 등 소식 게시글 목록 조회 및 상세 확인</li><li><strong>화면 형태</strong>: 목록 페이지 + 상세 페이지</li><li><strong>진입 경로</strong>: GNB &gt; 고객센터 &gt; 성원소식</li></ul><hr><h2 id="■-화면-구조" tabindex="-1">■ 화면 구조 <a class="header-anchor" href="#■-화면-구조" aria-label="Permalink to &quot;■ 화면 구조&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>공지사항 (성원소식)</span></span>
<span class="line"><span>  ├─ [카테고리 탭] 전체 / 안내 / 긴급공지 / 이벤트 / 기타 / 공모전 / 보도자료</span></span>
<span class="line"><span>  ├─ [게시글 목록]</span></span>
<span class="line"><span>  │   ├─ 공지 뱃지 + 카테고리 뱃지 + 제목 + 작성일</span></span>
<span class="line"><span>  │   └─ 페이징</span></span>
<span class="line"><span>  └─ [검색] 검색어 입력 + 검색 버튼</span></span></code></pre></div><hr><h2 id="■-목록-화면-field-rule" tabindex="-1">■ 목록 화면 Field Rule <a class="header-anchor" href="#■-목록-화면-field-rule" aria-label="Permalink to &quot;■ 목록 화면 Field Rule&quot;">​</a></h2><h3 id="카테고리-탭" tabindex="-1">[카테고리 탭] <a class="header-anchor" href="#카테고리-탭" aria-label="Permalink to &quot;[카테고리 탭]&quot;">​</a></h3><ul><li><strong>필수 여부</strong>: 선택 (기본값: 전체)</li><li><strong>탭 구성</strong>: 전체 / 안내 / 긴급공지 / 이벤트 / 기타 / 공모전 / 보도자료</li><li><strong>탭 구성 방식</strong>: 하드코딩 (고정, 관리자 변경 불가)</li><li><strong>탭-분류 매핑 기준</strong>:</li></ul><table tabindex="0"><thead><tr><th>탭</th><th>포함 분류 (DB 카테고리)</th></tr></thead><tbody><tr><td>전체</td><td>위 분류 전체</td></tr><tr><td>안내</td><td>휴무안내, 택배안내, 배송안내, 정책안내, 회계안내, 상품안내, 출고안내, 시스템안내</td></tr><tr><td>긴급공지</td><td>긴급공지</td></tr><tr><td>이벤트</td><td>이벤트</td></tr><tr><td>공모전</td><td>공모전</td></tr><tr><td>보도자료</td><td>보도자료</td></tr><tr><td>기타</td><td>기타</td></tr></tbody></table><ul><li><strong>게시글 카테고리 뱃지</strong>: 탭 명칭이 아닌 DB 분류명 그대로 표시 (예: 휴무안내, 출고안내, 긴급공지 등)</li><li><strong>UI 정책</strong>: <ul><li>탭 선택 시 해당 탭에 매핑된 분류의 게시글만 필터링하여 목록 갱신</li><li>탭 전환 시 검색어 초기화 및 1페이지로 이동</li><li>현재 선택된 탭 강조 표시</li></ul></li></ul><h3 id="게시글-목록" tabindex="-1">[게시글 목록] <a class="header-anchor" href="#게시글-목록" aria-label="Permalink to &quot;[게시글 목록]&quot;">​</a></h3><ul><li><strong>정렬 기준</strong>: 작성일 내림차순 (최신순)</li><li><strong>공지 뱃지 게시글 처리</strong>: <ul><li>관리자가 게시글 등록 시 공지 여부 직접 지정</li><li>공지 뱃지 게시글은 목록 최상단에 항상 고정 표시</li><li>공지 고정 게시글이 복수일 경우 작성일 내림차순 정렬</li><li>공지 게시글 이하 일반 게시글도 작성일 내림차순 정렬</li></ul></li><li><strong>페이지당 노출 건수</strong>: 20건</li><li><strong>표시 항목</strong>: <ul><li>공지 뱃지 (공지 게시글에 한함)</li><li>카테고리 뱃지 (예: 휴무안내, 출고안내, 정책안내 등)</li><li>제목</li><li>작성일 (예: 2025 07 14)</li></ul></li><li><strong>UI 정책</strong>: <ul><li>게시글 제목 클릭 시 상세 화면으로 이동</li><li>게시글이 없을 경우: &quot;등록된 게시글이 없어요&quot; 안내 문구 표시</li></ul></li></ul><h3 id="검색" tabindex="-1">[검색] <a class="header-anchor" href="#검색" aria-label="Permalink to &quot;[검색]&quot;">​</a></h3><ul><li><strong>필수 여부</strong>: 선택</li><li><strong>검색 범위</strong>: 제목 + 내용 모두 검색</li><li><strong>입력 규칙</strong>: 자유 텍스트 입력</li><li><strong>UI 정책</strong>: <ul><li>Placeholder: &quot;제목 또는 내용을 입력해주세요&quot;</li><li>검색 버튼 클릭 또는 Enter 키 입력 시 검색 실행</li><li>검색 결과 없음 시: &quot;검색 결과가 없어요&quot; 안내 문구 표시</li><li>검색 실행 시 1페이지로 이동</li><li>카테고리 탭 전환 시 검색어 초기화</li></ul></li></ul><h3 id="페이징" tabindex="-1">[페이징] <a class="header-anchor" href="#페이징" aria-label="Permalink to &quot;[페이징]&quot;">​</a></h3><ul><li><strong>표시 방식</strong>: 페이지 번호 버튼 (예: 1 2 3 4 5 6)</li><li><strong>페이지당 노출 건수</strong>: 20건</li><li><strong>UI 정책</strong>: <ul><li>현재 페이지 번호 강조 표시</li><li>이전/다음 페이지 이동 버튼 제공</li></ul></li></ul><hr><h2 id="■-상세-화면-field-rule" tabindex="-1">■ 상세 화면 Field Rule <a class="header-anchor" href="#■-상세-화면-field-rule" aria-label="Permalink to &quot;■ 상세 화면 Field Rule&quot;">​</a></h2><h3 id="게시글-상세-정보" tabindex="-1">[게시글 상세 정보] <a class="header-anchor" href="#게시글-상세-정보" aria-label="Permalink to &quot;[게시글 상세 정보]&quot;">​</a></h3><ul><li><strong>표시 항목</strong>: <ul><li>공지/카테고리 뱃지</li><li>제목</li><li>작성일</li><li>본문 (텍스트 및 이미지 포함)</li><li>첨부파일 목록 (첨부파일이 있는 경우)</li></ul></li><li><strong>UI 정책</strong>: <ul><li>본문 내 이미지 인라인 표시</li><li>첨부파일 클릭 시 즉시 다운로드</li></ul></li></ul><h3 id="첨부파일" tabindex="-1">[첨부파일] <a class="header-anchor" href="#첨부파일" aria-label="Permalink to &quot;[첨부파일]&quot;">​</a></h3><ul><li><strong>다운로드 권한</strong>: 비회원 포함 누구나 다운로드 가능 (로그인 불필요)</li><li><strong>표시 형식</strong>: 파일명 + 다운로드 링크</li><li><strong>UI 정책</strong>: <ul><li>첨부파일이 없는 게시글은 첨부파일 영역 미노출</li></ul></li></ul><h3 id="이전-다음-게시글-이동" tabindex="-1">[이전 / 다음 게시글 이동] <a class="header-anchor" href="#이전-다음-게시글-이동" aria-label="Permalink to &quot;[이전 / 다음 게시글 이동]&quot;">​</a></h3><ul><li><strong>이동 기준</strong>: 전체 게시글 기준 (카테고리 무관)</li><li><strong>정렬 기준</strong>: 작성일 기준</li><li><strong>UI 정책</strong>: <ul><li>이전 글 없을 경우: &quot;이전 글이 없습니다&quot; 표시 또는 비활성화</li><li>다음 글 없을 경우: &quot;다음 글이 없습니다&quot; 표시 또는 비활성화</li></ul></li></ul><h3 id="목록-버튼" tabindex="-1">[목록 버튼] <a class="header-anchor" href="#목록-버튼" aria-label="Permalink to &quot;[목록 버튼]&quot;">​</a></h3><ul><li><strong>동작</strong>: 공지사항 목록 화면으로 이동</li><li><strong>이동 위치</strong>: 이전에 조회하던 페이지 번호 유지 (세션 기반 복귀)</li></ul><hr><h2 id="■-화면-플로우" tabindex="-1">■ 화면 플로우 <a class="header-anchor" href="#■-화면-플로우" aria-label="Permalink to &quot;■ 화면 플로우&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[GNB &gt; 고객센터 &gt; 성원소식]</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>[공지사항 목록]</span></span>
<span class="line"><span>  ├─ 카테고리 탭 선택 → 필터링된 목록 표시</span></span>
<span class="line"><span>  ├─ 검색어 입력 → 제목+내용 검색 결과 표시</span></span>
<span class="line"><span>  ├─ 페이지 번호 클릭 → 해당 페이지 목록 표시</span></span>
<span class="line"><span>  └─ 게시글 클릭</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>      [공지사항 상세]</span></span>
<span class="line"><span>        ├─ 첨부파일 클릭 → 파일 다운로드</span></span>
<span class="line"><span>        ├─ [이전] 클릭 → 전체 기준 이전 게시글 상세</span></span>
<span class="line"><span>        ├─ [다음] 클릭 → 전체 기준 다음 게시글 상세</span></span>
<span class="line"><span>        └─ [목록] 클릭 → 공지사항 목록 화면 이동</span></span></code></pre></div><hr><h2 id="■-예외-상황" tabindex="-1">■ 예외 상황 <a class="header-anchor" href="#■-예외-상황" aria-label="Permalink to &quot;■ 예외 상황&quot;">​</a></h2><h3 id="검색-결과-없음" tabindex="-1">[검색 결과 없음] <a class="header-anchor" href="#검색-결과-없음" aria-label="Permalink to &quot;[검색 결과 없음]&quot;">​</a></h3><ul><li><strong>처리</strong>: &quot;검색 결과가 없어요&quot; 안내 문구 표시</li><li><strong>재시도</strong>: 검색어 수정 후 재검색 가능</li></ul><h3 id="게시글-없음" tabindex="-1">[게시글 없음] <a class="header-anchor" href="#게시글-없음" aria-label="Permalink to &quot;[게시글 없음]&quot;">​</a></h3><ul><li><strong>처리</strong>: &quot;등록된 게시글이 없어요&quot; 안내 문구 표시</li></ul><h3 id="첨부파일-다운로드-오류" tabindex="-1">[첨부파일 다운로드 오류] <a class="header-anchor" href="#첨부파일-다운로드-오류" aria-label="Permalink to &quot;[첨부파일 다운로드 오류]&quot;">​</a></h3><ul><li><strong>처리</strong>: 에러 메시지 표시</li><li><strong>재시도</strong>: 사용자가 다시 클릭하여 재시도 가능</li></ul><h3 id="네트워크-오류" tabindex="-1">[네트워크 오류] <a class="header-anchor" href="#네트워크-오류" aria-label="Permalink to &quot;[네트워크 오류]&quot;">​</a></h3><ul><li><strong>처리</strong>: 에러 메시지 표시 및 재시도 유도</li></ul><hr><h2 id="■-필요-화면-목록" tabindex="-1">■ 필요 화면 목록 <a class="header-anchor" href="#■-필요-화면-목록" aria-label="Permalink to &quot;■ 필요 화면 목록&quot;">​</a></h2><p>현재 화면 플로우에서 필요하지만 추가 정의가 필요한 화면:</p><ol><li><strong>관리자 공지사항 등록/수정 화면</strong> - 게시글 등록 시 공지 여부, 카테고리 지정 기능 포함</li></ol>`,45)])])}const g=a(s,[["render",e]]);export{p as __pageData,g as default};
